#include <bits/stdc++.h>
using namespace std;

bool Time[505];
struct game {
    int t, r;
} g[505];

bool cmp(game a, game b) {
    if (a.r == b.r) {
        return a.t > b.t;
    }
    return a.r > b.r;
}

int main() {
    int n, c = 0;
    cin >> n;
    for (int i = 1; i <= n; i++) {
        cin >> g[i].t;
    }
    for (int i = 1; i <= n; i++) {
        cin >> g[i].r;
    }
    sort(g + 1, g + n + 1, cmp);
    // for (int i = 1; i <= n; i++) {
    //     printf("%d %d %d\n", i, g[i].t, g[i].r);
    // }
    for (int i = 1; i <= n; i++) {
        int j = g[i].t;
        for (; j >= 1 && Time[j]; j--);
        if (j >= 1) {
            Time[j] = true;
            c += g[i].r;
            // printf("%d %d %d\n", j, g[i].t, g[i].r);
        }
    }
    cout << c;
    return 0;
}
